Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream >> packet.packet_id;

    // Read username using length prefix
    stream >> hexi::prefixed(packet.username);

    // Read scores count and then the scores vector
    uint32_t score_count;
    stream >> hexi::prefixed(score_count);
    packet.scores.resize(score_count);
    for (auto& score : packet.scores) {
        stream >> score;
    }

    // Read metadata as null-terminated string for zero-copy
    std::string_view metadata_view;
    stream >> hexi::cstring(metadata_view);
    packet.metadata = metadata_view; // Convert to std::string (copy)

    // Skip any remaining padding bytes
    stream.skip(adaptor.remaining());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for packet_id (first 4 bytes) - zero-copy view
    auto packet_id_span = stream.span<4>();
    info.packet_id = *reinterpret_cast<const uint32_t*>(packet_id_span.data());

    // Read username using prefixed adaptor to get string_view
    stream >> hexi::prefixed(info.username);

    // Skip scores vector: read count, then skip the data
    uint32_t score_count;
    stream >> hexi::prefixed(score_count);
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}
```

Key points about the implementation:

1. **deserialize_packet**:
   - Uses `hexi::prefixed` for the username to read the length-prefixed string
   - Reads the score count first, then resizes the vector and reads each score individually
   - Uses `hexi::cstring` for zero-copy reading of the null-terminated metadata, then copies to std::string
   - Skips any remaining padding using `stream.skip(adaptor.remaining())`

2. **extract_packet_info**:
   - Uses `stream.span<4>()` for zero-copy access to the packet_id
   - Uses `hexi::prefixed` to get a `std::string_view` of the username without copying
   - Reads the score count but skips the actual score data using `stream.skip()`

Both functions use Hexi's buffer adaptor and binary stream to handle the serialization format efficiently with zero-copy operations where possible.

