std::vector<uint32_t> read_item_batch(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the read-only span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor);

    // Read the item count (uint32_t)
    uint32_t item_count;
    stream >> item_count;

    // Use read_container to read all items into a vector
    std::vector<uint32_t> items;
    stream >> hexi::read_container(items, item_count);

    return items;
}
```

