```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Preview the first byte (data_type) without advancing the read pointer
    auto preview_type = stream.preview<uint8_t>();
    if (!preview_type) {
        // Error previewing data, return empty result
        return result;
    }

    result.data_type = *preview_type;

    // Read the data_type (this advances the pointer after preview)
    stream >> result.data_type;

    // Read the item_count
    uint32_t item_count = 0;
    stream >> item_count;

    // Check if we have enough data for all items
    size_t required_bytes = 0;
    if (result.data_type == 0) { // integers
        required_bytes = item_count * sizeof(uint32_t);
    } else if (result.data_type == 1) { // floats
        required_bytes = item_count * sizeof(float);
    }

    // Verify we have enough data in the buffer
    if (stream.available() < required_bytes) {
        // Not enough data, return what we have (empty items)
        return result;
    }

    // Read items based on data type
    if (result.data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (result.data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}
```

