```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block allocator for uint32_t elements
    hexi::block_allocator<uint32_t, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " elements\n\n";

    // Demonstrate initial state - free list should contain all blocks
    std::cout << "1. Initial state:\n";
    std::cout << "   Free list contains all " << element_count << " blocks\n";
    std::cout << "   Available blocks: " << (element_count - allocator.total_allocs() + allocator.total_deallocs()) << "\n\n";

    // Allocate some blocks - these will be popped from free list
    std::cout << "2. Allocating 3 blocks:\n";
    uint32_t* block1 = allocator.allocate();
    uint32_t* block2 = allocator.allocate();
    uint32_t* block3 = allocator.allocate();

    if (block1 && block2 && block3) {
        std::cout << "   Successfully allocated blocks at: " 
                  << static_cast<void*>(block1) << ", "
                  << static_cast<void*>(block2) << ", "
                  << static_cast<void*>(block3) << "\n";
        std::cout << "   Available blocks after allocation: " 
                  << (element_count - allocator.total_allocs() + allocator.total_deallocs()) << "\n\n";
    }

    // Deallocate one block - it will be pushed back to free list
    std::cout << "3. Deallocating block2:\n";
    allocator.deallocate(block2);
    std::cout << "   Block returned to free list (LIFO order)\n";
    std::cout << "   Available blocks after deallocation: " 
              << (element_count - allocator.total_allocs() + allocator.total_deallocs()) << "\n\n";

    // Allocate again - should get the most recently freed block (LIFO behavior)
    std::cout << "4. Allocating another block:\n";
    uint32_t* block4 = allocator.allocate();
    if (block4) {
        std::cout << "   New block allocated at: " << static_cast<void*>(block4) << "\n";
        std::cout << "   This should be the same as block2's address due to LIFO free list\n";
        std::cout << "   Available blocks: " 
                  << (element_count - allocator.total_allocs() + allocator.total_deallocs()) << "\n\n";
    }

    // Demonstrate full allocation
    std::cout << "5. Allocating remaining blocks:\n";
    std::array<uint32_t*, element_count - 3> remaining_blocks{};
    for (size_t i = 0; i < element_count - 3; ++i) {
        remaining_blocks[i] = allocator.allocate();
    }
    std::cout << "   Allocated " << (element_count - 3) << " more blocks\n";
    std::cout << "   Available blocks: " 
              << (element_count - allocator.total_allocs() + allocator.total_deallocs()) << "\n";
    std::cout << "   Free list should now be empty\n\n";

    // Try to allocate one more (should fail)
    std::cout << "6. Attempting overallocation:\n";
    uint32_t* overflow = allocator.allocate();
    if (!overflow) {
        std::cout << "   Allocation failed as expected - free list is empty\n\n";
    }

    // Deallocate all blocks - they get pushed back to free list
    std::cout << "7. Deallocating all blocks:\n";
    allocator.deallocate(block1);
    allocator.deallocate(block3);
    allocator.deallocate(block4);
    for (auto* block : remaining_blocks) {
        allocator.deallocate(block);
    }
    std::cout << "   All blocks returned to free list\n";
    std::cout << "   Available blocks: " 
              << (element_count - allocator.total_allocs() + allocator.total_deallocs()) << "\n";
    std::cout << "   Free list now contains all " << element_count << " blocks again\n\n";

    std::cout << "=== Demonstration Complete ===\n";
    std::cout << "Summary:\n";
    std::cout << "- push() adds blocks to head of free list (LIFO)\n";
    std::cout << "- pop() removes blocks from head of free list (LIFO)\n";
    std::cout << "- This provides efficient allocation/deallocation with O(1) complexity\n";
}

// Example usage
int main() {
    demonstrate_block_allocator_behavior<10>();
    return 0;
}
```

This implementation demonstrates how the block allocator manages its free list internally using the LIFO (Last-In-First-Out) principle through `push()` and `pop()` operations. The key points shown are:

1. **Initial State**: All blocks are in the free list
2. **Allocation**: Blocks are `pop()`ped from the head of the free list
3. **Deallocation**: Blocks are `push()`ed to the head of the free list
4. **LIFO Behavior**: The most recently freed block is the next to be allocated
5. **Capacity Management**: The allocator properly handles full and empty states

The demonstration shows the internal free list management without directly accessing the private `push()` and `pop()` methods, by observing the allocation patterns and addresses.

