```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path);

    // Get the actual readable size (min of requested bytes and file size)
    size_t actual_size = std::min(bytes_to_read, buffer.size());

    std::vector<uint8_t> data(actual_size);
    if (actual_size > 0) {
        buffer.read(data.data(), actual_size);
    }
    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    hexi::file_buffer buffer(file_path);

    // Get the current position to restore later
    size_t current_pos = buffer.tell();

    // Get the actual preview size (min of requested bytes and remaining data)
    size_t actual_size = std::min(bytes_to_preview, buffer.size() - current_pos);

    std::vector<uint8_t> data(actual_size);
    if (actual_size > 0) {
        buffer.read(data.data(), actual_size);
        // Restore the original position
        buffer.seek(current_pos);
    }
    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    hexi::file_buffer buffer(file_path);

    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path);
    return buffer.size();
}
```

