Looking at the provided code fragments, I can see that Hexi uses a `file_buffer` class and `binary_stream` for reading/writing operations. Here's the complete implementation:

```cpp
#include <hexi/file_buffer.h>
#include <cstdint>
#include <filesystem>

uint32_t read_uint32_from_file(const std::filesystem::path& file_path) {
    // Create a file_buffer for reading
    hexi::file_buffer buffer(file_path.string().c_str());

    // Check if file was opened successfully
    if (buffer.error()) {
        throw std::runtime_error("Failed to open file for reading");
    }

    // Create a binary stream from the buffer
    hexi::binary_stream stream(buffer);

    // Read the uint32_t value
    uint32_t value;
    stream >> value;

    // Check if read was successful
    if (!stream) {
        throw std::runtime_error("Failed to read uint32 from file");
    }

    return value;
}

void write_uint32_to_file(const std::filesystem::path& file_path, uint32_t value) {
    // Create a file_buffer for writing (opens in append mode "a+b")
    hexi::file_buffer buffer(file_path.string().c_str());

    // Check if file was opened successfully
    if (buffer.error()) {
        throw std::runtime_error("Failed to open file for writing");
    }

    // Create a binary stream from the buffer
    hexi::binary_stream stream(buffer);

    // Write the uint32_t value
    stream << value;

    // Check if write was successful
    if (!stream) {
        throw std::runtime_error("Failed to write uint32 to file");
    }
}
```

