#include <vector>
#include <cstdint>

const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Get the current read pointer by accessing the element at index 0
    // The operator[] returns a reference to the byte at the given index
    if (buffer.empty()) {
        return nullptr;
    }
    return &buffer[0];
}

struct BufferState {
    std::size_t size;
    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferState state;
    state.size = buffer.size();
    state.is_empty = buffer.empty();
    state.read_ptr = state.is_empty ? nullptr : &buffer[0];
    return state;
}
```

