#include <hexi/shared.h>
#include <vector>
#include <cstdint>

bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    return buffer.can_write_seek();
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Write header placeholder at the beginning
    uint32_t placeholder = 0;
    buffer.write_seek(hexi::buffer_seek::begin, 0);
    buffer.write(&placeholder, sizeof(placeholder));

    // Get the current position after writing the placeholder
    // Since we can't directly get the position, we'll calculate it
    // The position should be at sizeof(uint32_t) from the beginning
    std::size_t body_start_position = sizeof(uint32_t);

    // Write body content starting after the header
    buffer.write_seek(hexi::buffer_seek::begin, body_start_position);

    // Example body data
    std::vector<std::byte> body_data = {std::byte{0x01}, std::byte{0x02}, std::byte{0x03}};
    buffer.write(body_data.data(), body_data.size());

    // Seek back to beginning to update the header with the actual value
    buffer.write_seek(hexi::buffer_seek::begin, 0);
    buffer.write(&header_value, sizeof(header_value));

    // Seek to the end to continue writing after the body
    buffer.write_seek(hexi::buffer_seek::end, 0);
}
