#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle the case where T is signed - convert to unsigned representation
    using UnsignedT = std::make_unsigned_t<T>;
    UnsignedT unsigned_value;

    if constexpr (std::is_signed_v<T>) {
        // For signed values, use zigzag encoding
        unsigned_value = (static_cast<UnsignedT>(value) << 1) ^ (static_cast<UnsignedT>(value) >> (sizeof(T) * 8 - 1));
    } else {
        unsigned_value = static_cast<UnsignedT>(value);
    }

    // Encode the unsigned value using varint encoding
    do {
        uint8_t byte = static_cast<uint8_t>(unsigned_value & 0x7F);
        unsigned_value >>= 7;

        if (unsigned_value != 0) {
            byte |= 0x80; // Set continuation bit
        }

        writer.write(byte);
        bytes_written++;

    } while (unsigned_value != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using UnsignedT = std::make_unsigned_t<T>;
    UnsignedT result = 0;
    int shift = 0;

    while (true) {
        uint8_t byte = reader.template read<uint8_t>();
        result |= static_cast<UnsignedT>(byte & 0x7F) << shift;
        shift += 7;

        if ((byte & 0x80) == 0) {
            break; // Last byte
        }

        // Prevent overflow for the type
        if (shift >= static_cast<int>(sizeof(T) * 8)) {
            break;
        }
    }

    if constexpr (std::is_signed_v<T>) {
        // For signed values, use zigzag decoding
        return static_cast<T>((result >> 1) ^ (-(result & 1)));
    } else {
        return static_cast<T>(result);
    }
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::byte> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Create a writer and encode the value
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint<T>(writer, original_value);

    // Check if encoding was successful
    if (writer.state() != stream_state::ok) {
        return false;
    }

    // Create a reader and decode the value
    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    T decoded_value = decode_varint<T>(reader);

    // Check if decoding was successful
    if (reader.state() != stream_state::ok) {
        return false;
    }

    // Compare the original and decoded values
    return original_value == decoded_value;
}
