std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to write to
    std::vector<uint8_t> buffer;

    // Create a write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    std::size_t total_written = 0;

    for (const auto& chunk : chunks) {
        // Check available space before each write
        std::size_t available_space = adaptor.free();

        // Determine how much we can write (in case buffer has limited capacity)
        std::size_t write_size = std::min(chunk.size(), available_space);

        if (write_size > 0) {
            // Write the chunk data
            adaptor.write(chunk.data(), write_size);
            total_written += write_size;
        }

        // If we couldn't write the entire chunk due to space constraints,
        // we might want to handle this case. For simplicity, we'll just
        // write what we can and continue.
        if (write_size < chunk.size()) {
            // Optional: Resize buffer or handle partial write
            // For now, we'll just skip the remaining data
        }
    }

    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a read adaptor for the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Check remaining data
        std::size_t remaining = adaptor.size();
        std::size_t read_size = std::min(chunk_size, remaining);

        if (read_size > 0) {
            // Create temporary buffer for reading
            std::vector<uint8_t> temp(read_size);

            // Read the data
            adaptor.read(temp.data(), read_size);

            // Append to result
            result.insert(result.end(), temp.begin(), temp.end());
        }
    }

    return result;
}
```

