#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialize sensor_id directly
        adaptor(sensor_id);

        // Serialize temperatures with endianness conversion
        uint32_t temp_count = static_cast<uint32_t>(temperatures.size());
        adaptor(temp_count);

        for (const float& temp : temperatures) {
            float le_temp = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(&le_temp, sizeof(le_temp));
        }

        // Serialize pressure with endianness conversion
        double le_pressure = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(&le_pressure, sizeof(le_pressure));
    }

    void serialise(auto& adaptor) {
        // Deserialize sensor_id directly
        adaptor(sensor_id);

        // Deserialize temperatures count
        uint32_t temp_count;
        adaptor(temp_count);

        // Resize vector and deserialize temperatures with endianness conversion
        temperatures.resize(temp_count);
        for (float& temp : temperatures) {
            adaptor.read(&temp, sizeof(temp));
            hexi::little_to_native_inplace(temp);
        }

        // Deserialize pressure with endianness conversion
        adaptor.read(&pressure, sizeof(pressure));
        hexi::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData data;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;
    hexi::buffer_adaptor adaptor(buffer);

    // Extract null-terminated sensor name if present
    info.sensor_name = adaptor.view();

    // Check bounds before reading sensor_id
    adaptor.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    adaptor.read(&info.sensor_id, sizeof(info.sensor_id));

    // Skip remaining data
    adaptor.skip(adaptor.remaining());

    return info;
}
